import React from 'react';
import toast from 'react-hot-toast';

const REPORTS = [
  {icon:'💰',title:'Fee Reports',desc:'Daily, monthly, class-wise collections & pending dues',tags:['PDF','Excel']},
  {icon:'✅',title:'Attendance Reports',desc:'Student & staff monthly attendance summaries',tags:['PDF','Excel']},
  {icon:'📝',title:'Exam Results',desc:'Class-wise results, ranks, grades and report cards',tags:['PDF']},
  {icon:'👨‍🎓',title:'Student Reports',desc:'Admission, promotion, TC and student summaries',tags:['PDF','Excel']},
  {icon:'💳',title:'Salary Reports',desc:'Monthly payroll, salary register & slip generation',tags:['PDF','Excel']},
  {icon:'🚌',title:'Transport Reports',desc:'Route-wise and vehicle-wise student transport data',tags:['PDF','Excel']},
];

export default function Reports() {
  return (
    <div>
      <div style={{marginBottom:20}}>
        <h2 style={{fontSize:20,fontWeight:700}}>Reports & Analytics</h2>
        <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>Generate and export comprehensive reports</p>
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:14}}>
        {REPORTS.map(r=>(
          <div key={r.title} onClick={()=>toast.success(`Generating ${r.title}…`)}
            style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:'24px 18px',cursor:'pointer',transition:'all .18s',textAlign:'center'}}
            onMouseEnter={e=>e.currentTarget.style.transform='translateY(-3px)'}
            onMouseLeave={e=>e.currentTarget.style.transform=''}>
            <div style={{fontSize:34,marginBottom:10}}>{r.icon}</div>
            <div style={{fontSize:13,fontWeight:700,marginBottom:6}}>{r.title}</div>
            <div style={{fontSize:11,color:'#6B7280',marginBottom:14,lineHeight:1.5}}>{r.desc}</div>
            <div style={{display:'flex',gap:6,justifyContent:'center'}}>
              {r.tags.map(t=>(
                <span key={t} style={{padding:'2px 10px',borderRadius:20,fontSize:10,fontWeight:600,background:t==='PDF'?'#EDE9F8':'#D1FAE5',color:t==='PDF'?'#2D1B69':'#065F46'}}>{t}</span>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
